from sol import topo_sort
order = topo_sort({'a':['b'],'b':['c'],'c':[]})
pos = {n:i for i,n in enumerate(order)}
assert pos['a']<pos['b']<pos['c']
assert topo_sort({}) == []
assert set(topo_sort({'x':[],'y':[]})) == {'x','y'}
try:
    topo_sort({'a':['b'],'b':['a']})
    raise SystemExit('cycle not detected')
except ValueError:
    pass
print('PASS')

from sol import retry
calls={'n':0}
def flaky():
    calls['n']+=1
    if calls['n']<3: raise ValueError('boom')
    return 'ok'
assert retry(flaky, attempts=3)=='ok'
assert calls['n']==3
calls2={'n':0}
def always_fail():
    calls2['n']+=1
    raise RuntimeError('nope')
try:
    retry(always_fail, attempts=2)
    raise SystemExit('should have re-raised')
except RuntimeError:
    pass
assert calls2['n']==2
print('PASS')
